export function firebaseAppFactory(fn: (injector: Injector) => IFirebaseApp) {
  return (zone: NgZone, injector: Injector) => {
    const platformId = injector.get(PLATFORM_ID);
    registerVersion('angularfire', VERSION.full, 'core');
    registerVersion('angularfire', VERSION.full, 'app');
    // eslint-disable-next-line @typescript-eslint/no-base-to-string
    registerVersion('angular', NG_VERSION.full, platformId.toString());

    const app = zone.runOutsideAngular(() => fn(injector));
    return new FirebaseApp(app);
  };
}

export function listChanges<T = any>(ref: DatabaseQuery, events: ChildEvent[], scheduler?: SchedulerLike): Observable<SnapshotAction<T>[]> {
  return fromRef(ref, 'value', 'once', scheduler).pipe(
    switchMap(snapshotAction => {
      const childEvent$ = [of(snapshotAction)];
      events.forEach(event => childEvent$.push(fromRef(ref, event, 'on', scheduler)));
      return merge(...childEvent$).pipe(scan(buildView, []));
    }),
    distinctUntilChanged()
  );
}

export function sortedChanges<T>(
  query: Query,
  events: DocumentChangeType[],
  scheduler?: SchedulerLike): Observable<DocumentChangeAction<T>[]> {
  return docChanges<T>(query, scheduler)
    .pipe(
      scan((current, changes) => combineChanges<T>(current, changes.map(it => it.payload), events), []),
      distinctUntilChanged(), // cut down on unneed change cycles
      map(changes => changes.map(c => ({ type: c.type, payload: c } as DocumentChangeAction<T>))));
}

export function updateValidity(c: AbstractControl, onlySelf = false) {
  const status = c.status;
  const value = c.value;
  c.updateValueAndValidity({ emitEvent: false, onlySelf });
  if (status !== c.status) {
    (c.statusChanges as EventEmitter<string>).emit(c.status);
  }

  if (value !== c.value) {
    (c.valueChanges as EventEmitter<any>).emit(c.value);
  }
}

export function forwardRef(forwardRefFn: ForwardRefFn): Type<any> {
  (<any>forwardRefFn).__forward_ref__ = forwardRef;
  if (ngDevMode) {
    (<any>forwardRefFn).toString = function () {
      return stringify(this());
    };
  }

  return <Type<any>>(<any>forwardRefFn);
}

setType(options: TypeOption | TypeOption[]) {
  if (Array.isArray(options)) {
    options.forEach((option) => this.setType(option));
  } else {
    if (!this.types[options.name]) {
      this.types[options.name] = <TypeOption>{ name: options.name };
    }

    (['component', 'extends', 'defaultOptions', 'wrappers'] as (keyof TypeOption)[]).forEach((prop) => {
      if (options.hasOwnProperty(prop)) {
        this.types[options.name][prop] = options[prop] as any;
      }
    });
  }
}

add(i?: number, initialModel?: any, { markAsDirty } = { markAsDirty: true }) {
  markAsDirty && this.formControl.markAsDirty();
  i = i == null ? this.field.fieldGroup.length : i;
  if (!this.model) {
    assignFieldValue(this.field, []);
  }

  this.model.splice(i, 0, initialModel ? clone(initialModel) : undefined);
  this.markFieldForCheck(this.field.fieldGroup[i]);
  this._build();
}

remove(i: number, { markAsDirty } = { markAsDirty: true }) {
  markAsDirty && this.formControl.markAsDirty();
  this.model.splice(i, 1);

  const field = this.field.fieldGroup[i];
  this.field.fieldGroup.splice(i, 1);
  this.field.fieldGroup.forEach((f, key) => this.updateArrayElementKey(f, `${key}`));
  unregisterControl(field, true);
  this._build();
}

onChange(value: any, checked: boolean) {
  this.formControl.markAsDirty();
  if (this.props.type === 'array') {
    this.formControl.patchValue(
      checked
        ? [...(this.formControl.value || []), value]
        : [...(this.formControl.value || [])].filter((o) => o !== value),
    );
  } else {
    this.formControl.patchValue({ ...this.formControl.value, [value]: checked });
  }
  this.formControl.markAsTouched();
}

calcSortClass(sortDir: SortDirection | undefined): string[] | undefined {
  if (!this.cellContext().column.sortable) {
    return undefined;
  }
  if (sortDir === 'asc') {
    return ['sort-btn', 'sort-asc', this.sortAscendingIcon() ?? 'datatable-icon-up'];
  } else if (sortDir === 'desc') {
    return ['sort-btn', 'sort-desc', this.sortDescendingIcon() ?? 'datatable-icon-down'];
  } else {
    return ['sort-btn', this.sortUnsetIcon() ?? 'datatable-icon-sort-unset'];
  }
}

applyStylesToKeyframe() {
  if (this._pendingStyles.size == 0) return;

  this._pendingStyles.forEach((val, prop) => {
    this._currentKeyframe.set(prop, val);
